section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/diagram-as-code-mermaid-structurizr.json",
  "title": "Diagram-as-Code with Mermaid / Structurizr",
  "type": "object",
  "required": [
    "artefact_id",
    "diagrams",
    "render_command",
    "ci_check",
    "doc_links",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "diagrams": {
      "type": "array",
      "minItems": 1,
      "description": "list of {path, type, c4_level?}"
    },
    "render_command": {
      "type": "string",
      "description": "CI command that renders all diagrams"
    },
    "ci_check": {
      "type": "string",
      "description": "CI job id that runs render_command and blocks on failure"
    },
    "doc_links": {
      "type": "array",
      "minItems": 1,
      "description": "list of {doc_path, diagram_path}"
    }
  },
  "additionalProperties": false
}
